package com.airlock.saas.config.service.domain.model

import com.airlock.saas.base.domain.model.Author
import com.airlock.saas.base.domain.model.stereotypes.Aggregate
import com.airlock.saas.ids.ConfigActivationId
import com.airlock.saas.ids.OrganizationId
import com.airlock.saas.ids.TenantId
import java.time.Instant
import java.time.temporal.ChronoUnit

@Aggregate
class ConfigActivation(
	val id: ConfigActivationId,
	val tenantId: TenantId,
	val organizationId: OrganizationId,
	val config: ConfigActivationConfig,
	val activationDate: Instant,
	val author: Author,
	var status: ConfigActivationStatus,
	var statusUpdatedDate: Instant? = null,
) {

	override fun equals(other: Any?): Boolean {
		if (this === other) return true
		if (other !is ConfigActivation) return false

		return id == other.id
	}

	override fun hashCode(): Int = id.hashCode()

	companion object {
		fun create(
			tenantId: TenantId,
			organizationId: OrganizationId,
			config: ConfigActivationConfig,
			activationDate: Instant,
			author: Author,
		): ConfigActivation =
			ConfigActivation(
				ConfigActivationId.random(),
				tenantId,
				organizationId,
				config,
				// We truncate to millisecond precision because MongoDB only supports millisecond precision.
				activationDate.truncatedTo(ChronoUnit.MILLIS),
				author,
				ConfigActivationStatus.PENDING,
			)
	}
}

